package com.mengwei.localgrowth.diagnostic;
import com.mengwei.localgrowth.identity.AuthService.Identity; import com.mengwei.localgrowth.shared.TenantAccess; import jakarta.validation.Valid; import jakarta.validation.constraints.NotNull; import java.util.*; import org.springframework.web.bind.annotation.*;
@RestController @RequestMapping("/api/v1") public class DiagnosticController {private final DiagnosticService service;private final TenantAccess access;public DiagnosticController(DiagnosticService s,TenantAccess a){service=s;access=a;}private Identity i(String h){return access.identity(h);}@PostMapping("/diagnostic-runs")public Map<String,Object> run(@RequestHeader("Authorization")String h,@Valid @RequestBody RunRequest r){return service.run(i(h),r.merchantId(),r.provider()==null?"MOCK":r.provider());}@GetMapping("/diagnostic-runs/{id}")public Map<String,Object> result(@RequestHeader("Authorization")String h,@PathVariable UUID id){return service.result(i(h),id);}public record RunRequest(@NotNull UUID merchantId,String provider){}}
